import{_ as h,o as t,c as o,ag as a}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"Hướng dẫn Hỗ trợ Phòng ban","description":"Các Use Case ứng dụng HappyAgent cho từng phòng ban chuyên môn tại Boxme","frontmatter":{"title":"Hướng dẫn Hỗ trợ Phòng ban","description":"Các Use Case ứng dụng HappyAgent cho từng phòng ban chuyên môn tại Boxme"},"headers":[],"relativePath":"sop/openclaw-business-guide.md","filePath":"sop/openclaw-business-guide.md"}'),i={name:"sop/openclaw-business-guide.md"};function c(e,n,g,l,r,s){return t(),o("div",null,[...n[0]||(n[0]=[a('<h1 id="cam-nang-happy-agent-danh-cho-non-tech-boxme" tabindex="-1">Cẩm Nang Happy Agent Dành Cho Non-Tech (Boxme) <a class="header-anchor" href="#cam-nang-happy-agent-danh-cho-non-tech-boxme" aria-label="Permalink to &quot;Cẩm Nang Happy Agent Dành Cho Non-Tech (Boxme)&quot;">​</a></h1><p>Chào mừng các bạn đến với tài liệu hướng dẫn ứng dụng <strong>Happy Agent</strong> - Cỗ máy tự động hoá vạn năng. Tài liệu này được thiết kế dành riêng cho các nhân sự khối Kinh doanh, Kế toán, Chăm sóc Khách hàng, Nhân sự, Vận hành... (Non-Tech) tại Boxme để có thể tận dụng AI một cách mạnh mẽ vào việc xử lý các tác vụ lặp đi lặp lại.</p><h2 id="_1-happy-agent-la-gi" tabindex="-1">1. Happy Agent là gì? <a class="header-anchor" href="#_1-happy-agent-la-gi" aria-label="Permalink to &quot;1. Happy Agent là gì?&quot;">​</a></h2><p>Happy Agent là một &quot;nhân viên ảo&quot; chạy trực tiếp trên máy tính của bạn. Thay vì phải nhấp chuột lặp đi lặp lại trên nhiều giao diện hay xử lý hàng ngàn dòng Excel thủ công, bạn chỉ cần cấu hình (hoặc ra lệnh), Happy Agent sẽ làm thay bạn: tải báo cáo, gửi tin nhắn hàng loạt, lọc dữ liệu, click hệ thống nội bộ, v.v.</p><p>Đặc biệt, hệ thống hoạt động trực tiếp trên máy bạn (Local) nên <strong>bảo mật tuyệt đối 100% dữ liệu</strong> và <strong>tiết kiệm chi phí API</strong>.</p><hr><h2 id="_2-cac-use-cases-thuc-chien-theo-tung-phong-ban" tabindex="-1">2. Các Use Cases Thực Chiến Theo Từng Phòng Ban <a class="header-anchor" href="#_2-cac-use-cases-thuc-chien-theo-tung-phong-ban" aria-label="Permalink to &quot;2. Các Use Cases Thực Chiến Theo Từng Phòng Ban&quot;">​</a></h2><p>Dưới đây là các ứng dụng (Playbook) thực tế mà các phòng ban tại Boxme có thể áp dụng ngay để cải thiện hiệu suất x10 lần.</p><h3 id="_2-1-phong-ho-tro-khach-hang-customer-support" tabindex="-1">2.1. Phòng Hỗ trợ Khách hàng (Customer Support) <a class="header-anchor" href="#_2-1-phong-ho-tro-khach-hang-customer-support" aria-label="Permalink to &quot;2.1. Phòng Hỗ trợ Khách hàng (Customer Support)&quot;">​</a></h3><p>Thay vì tra mã vận đơn bằng tay cho từng người, hãy để Agent tự động hóa:</p><ul><li><strong>Auto-Reply Ticket:</strong> Quét các tài khoản kênh khiếu nại (Email, Fanpage), lấy mẫu câu trả lời chuẩn mực và phản hồi hàng loạt các sự cố tương tự (báo giao trễ, hỏng hóc).</li><li><strong>Tra cứu trạng thái đơn:</strong> Tự động đọc mã đơn hàng mà khách nhắn qua Zalo/Chat, mở hệ thống ERP Boxme để xem tiến trình và tự phản hồi lại cho khách.</li><li><strong>Xin đánh giá 5 Sao:</strong> Nhắn tin xin feedback qua các sàn TMĐT (Shopee Chat/TikTok) ngay khi đơn hàng chuyển màu &quot;Đã Giao&quot;.</li></ul><h3 id="_2-2-phong-kinh-doanh-sales-bd" tabindex="-1">2.2. Phòng Kinh doanh (Sales / BD) <a class="header-anchor" href="#_2-2-phong-kinh-doanh-sales-bd" aria-label="Permalink to &quot;2.2. Phòng Kinh doanh (Sales / BD)&quot;">​</a></h3><p>Giao phần việc đi tìm số điện thoại cực nhọc cho AI:</p><ul><li><strong>Cào File Đối tác tiềm năng (Lead Generation):</strong> Quét các hội nhóm Facebook kinh doanh hoặc Top cửa hàng Shopee, lọc lấy Tên gian hàng, Số điện thoại, Email và đẩy thẳng lên CRM Boxme.</li><li><strong>Rải tin mời lên Sàn / Mời KOC (TikTok/Shopee):</strong> Gửi tin nhắn hợp tác hàng loạt đến hàng trăm Influencer theo kịch bản cá nhân hoá (tự gọi tên, tự theo ngách).</li></ul><h3 id="_2-3-phong-ke-toan-tai-chinh-finance" tabindex="-1">2.3. Phòng Kế toán &amp; Tài chính (Finance) <a class="header-anchor" href="#_2-3-phong-ke-toan-tai-chinh-finance" aria-label="Permalink to &quot;2.3. Phòng Kế toán &amp; Tài chính (Finance)&quot;">​</a></h3><p>Biến quá trình tải hoá đơn nhàm chán thành tự động:</p><ul><li><strong>Tải hoá đơn đỏ tự động:</strong> Đăng nhập vào các cổng hoá đơn điện tử của nhà cung cấp, tải file PDF/XML về thư mục máy tính và phân chia theo đúng cấu trúc Ngày-Tháng.</li><li><strong>Đối soát sao kê tĩnh:</strong> Lấy báo cáo từ cổng thanh toán, tự động mở ERP nội bộ và thao tác khớp lệnh các khoản tiền thu về.</li><li><strong>Cào dữ liệu Tỷ giá &amp; Lãi suất:</strong> Mỗi sáng tự động mở web ngân hàng, copy tỷ giá USD/VND hiện tại và báo cáo lên group Slack.</li></ul><h3 id="_2-4-doanh-thu-cong-no-revenue-cashflow" tabindex="-1">2.4. Doanh thu &amp; Công nợ (Revenue / Cashflow) <a class="header-anchor" href="#_2-4-doanh-thu-cong-no-revenue-cashflow" aria-label="Permalink to &quot;2.4. Doanh thu &amp; Công nợ (Revenue / Cashflow)&quot;">​</a></h3><ul><li><strong>Báo cáo Tiền về Đa sàn:</strong> Tối muộn, Agent đăng nhập vào các Seller Center (TikTok, Shopee, Lazada), tổng hợp số tiền đối soát chuẩn bị về và ném vào Group BOT Telegram.</li><li><strong>Nhắc nợ tự động:</strong> Dựa vào danh sách công nợ trên Excel, Agent login vào Zalo/Email để gửi tin nhắn nhắc nhở quá hạn thanh toán lịch sự tới tập KH trả sau của Boxme.</li></ul><h3 id="_2-5-phong-nhan-su-hr" tabindex="-1">2.5. Phòng Nhân sự (HR) <a class="header-anchor" href="#_2-5-phong-nhan-su-hr" aria-label="Permalink to &quot;2.5. Phòng Nhân sự (HR)&quot;">​</a></h3><ul><li><strong>Tự động đăng tin tuyển dụng đa kênh:</strong> Lấy thông tin JD từ Google Docs, tự động mở web (TopCV, VietnamWorks, LinkedIn), điền form và đẩy tin chuẩn SEO.</li><li><strong>Lọc CV hàng loạt:</strong> Mở list CV, trích xuất dữ liệu cơ bản (Tên, SDT, Kỹ năng) và copy tự động vào bảng Google Sheets quản lý ƯV.</li><li><strong>Bật/Tắt tài khoản Onboarding:</strong> Tự động điền Form cấp phát quyền (Slack, Jira, Git) khi có nhân viên mới, và tắt hàng loạt hệ thống khi có nhân sự offboard chỉ từ 1 file CSV.</li></ul><h3 id="_2-6-kho-van-fulfillment-operations" tabindex="-1">2.6. Kho vận (Fulfillment / Operations) <a class="header-anchor" href="#_2-6-kho-van-fulfillment-operations" aria-label="Permalink to &quot;2.6. Kho vận (Fulfillment / Operations)&quot;">​</a></h3><ul><li><strong>Phân tệp Nhãn dán tự động:</strong> Tải hàng ngàn tem vận đơn (PDF) từ hệ thống và tách thành từng thư mục nhỏ để máy in in dần theo kịch bản, không làm sập mạng cục bộ.</li><li><strong>Theo dõi Đơn Lỗi/Hoàn:</strong> Quét liên tục các Dashboard trạng thái. Tự động bóc tách các đơn hàng rớt/hỏng để kho có cảnh báo xử lý lập tức.</li></ul><hr><h2 id="_3-neu-toi-muon-day-happy-agent-lam-them-viec-khac-teach-skill" tabindex="-1">3. Nếu Tôi Muốn Dạy Happy Agent Làm Thêm Việc Khác? (Teach Skill) <a class="header-anchor" href="#_3-neu-toi-muon-day-happy-agent-lam-them-viec-khac-teach-skill" aria-label="Permalink to &quot;3. Nếu Tôi Muốn Dạy Happy Agent Làm Thêm Việc Khác? (Teach Skill)&quot;">​</a></h2><p>Bạn là chuyên gia trong công việc của mình. Nếu có tác vụ lặp nào đó chưa có trong list trên, bạn hoàn toàn có thể &quot;dạy&quot; Agent kỹ năng đó chỉ trong 3 bước:</p><ol><li><strong>Chuẩn bị SOP Mẫu</strong>: Làm thao tác chuẩn (Bấm nút nào, điền nội dung gì) 1 lần, quay lại video màn hình hoặc liệt kê bằng chữ.</li><li><strong>Kéo thả File vào Tab &quot;Dạy Skill&quot;</strong>: Mở phần mềm giao diện điều khiển (Dashboard) của hệ thống lên, kéo quy trình vận hành bạn vừa làm vào đó.</li><li>Thư giãn! Sức mạnh của AI sẽ hiểu quy trình bạn làm và biến thành 1 &quot;Kỹ năng chuyên biệt&quot; cho phòng ban của bạn có thể tái sử dụng về sau.</li></ol>',27)])])}const m=h(i,[["render",c]]);export{p as __pageData,m as default};
